fn staged_mixed_theory() -> (Theory, TheoryItem) {
    let x = var("x", SortHint::Untagged);
    let macros = TheoryItem::Macros(vec![
        mdef("m", &[x.clone()], pair(vec![msg("x"), msg("x")])),
        mdef("konst", &[], app("h", vec![publit("k")])),
