        TheoryItem::Rule(r) => Some(r), _ => None }).unwrap();
    assert_eq!(r.actions[0], fact("A", vec![pair(vec![msg("x"), msg("x")])]));

    // restriction formula expanded
    let restr = out.items.iter().find_map(|it| match it {
